		struct GAIA_API Core_ {};
		// struct EntityDesc;
		// struct Component;
		struct GAIA_API OnDelete_ {};
		struct GAIA_API OnDeleteTarget_ {};
		struct GAIA_API Remove_ {};
		struct GAIA_API Delete_ {};
